function [ dataf ] = pf2_lpf( data,ft,fs,freq_cut,Nf )% inputs ------------------------% data: data to be filtered% ft: filter type% fs: sampling freq.% freq_cut: cut-off frequency% Nf: filter length% outputs -----------------------% dataf: filtered data%--------------------------------% lpf function designs lowpass FIR filter with the specified cut-off frequency and length.% It filters the data columnwise as its output%--------------------------------[Mini,Nini]=size(data);if Mini==1 %if the data is a row vector converts it to column vector    data=data';end[M,N]=size(data);%-----------------------------------------------------------------% Low-pass Filter design%-----------------------------------------------------------------half_fs = fs/2;    %half of sampling freq. equal to piif ft==1    [b,a] = fir1(Nf,freq_cut/half_fs);  % use FIR1 to obtain linear phase filter; b=impulse response                                     elseif ft==2    dp=0.01; %pass-band ripple    ds=0.01; %stop-band ripple    dev=[dp ds];    F=[freq_cut freq_cut+0.1*(freq_cut)];   %these are the cutoff frequencies %this frequency depends on noise frequency    MR=[1 0];    [N1, F0, M0, W]=remezord(F, MR, dev, fs);    [b,delta]=remez(N1, F0, M0, W);    a=1;elseif ft==3    [b,a] = butter(Nf,freq_cut/half_fs);                     end%-----------------------------------------------------------------% Filter the data%-----------------------------------------------------------------%H = fft(b',2*(M+Nf));           %frequency domain filter%H = freqz(b,a,2*(M+Nf),'whole');           %frequency domain filter%H=H/(H(1));%Data = fft(data,2*(M+Nf));      %frequency domain data%Dataf = (H * ones(1,N)) .* Data;  %frequency domain filtered data%datad = ifft(Dataf);              %time domain filtered data   %dataf = (real(datad(Nf/2:M+Nf/2-1,1:N))); %adjustment for time shifting caused by the filterif(size(data,1)>3*Nf)    try        dataf=filtfilt(b,a,data);    catch        dataf=pf2_base.external.filtfilt_classic(b,a,data); % Use matlab 2018a filtfilt if current version fails due to nans    endelse    dataf=nan(size(data));     warning('LPF: Datasize must be larger than 3*filter length (%i samples)',Nf);endif Mini==1 %if the data is a row vector converts it to column vector    dataf=dataf';endendfunction dataf=nantolerant_filtfilt(b,a,data)    datamask=isnan(data)|isinf(data);        data(datamask)=nanmedian(data(:));    for i=1:size(data,2)       data(datamask(:,i),i)=nanmedian(data(:,i));     end    data(isnan(data))=0;        dataf=filtfilt(b,a,data);        dataf(datamask)=nan;end